const input = $input.first().json;
const action = input.action;

const MCP_URL = 'https://n8n.oi.destination.one/mcp/eb8571ff-96cf-4707-ad99-3c0fbe9b938f';
const MCP_HEADERS = { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream' };

// Build args from input, skip empty values
function buildArgs(keys) {
  const args = {};
  for (const k of keys) {
    if (input[k] !== undefined && input[k] !== '' && input[k] !== null) {
      args[k] = input[k];
    }
  }
  return args;
}

// Determine tool name and arguments
let toolName, toolArgs;
if (action === 'get_pois_by_criteria') {
  toolName = 'get_pois_by_criteria';
  toolArgs = buildArgs(['name', 'keywords', 'type', 'locality', 'region', 'postal_code', 'near_point']);
} else if (action === 'get_events_by_criteria') {
  toolName = 'get_events_by_criteria';
  toolArgs = buildArgs(['keywords', 'name', 'locality', 'dateRangeStart', 'dateRangeEnd', 'region']);
  if (!toolArgs.keywords) return [{ json: { error: 'Parameter "keywords" is required for event search (e.g. "Musik,Konzert", "Wein,Weinprobe").' } }];
  if (!toolArgs.dateRangeStart) return [{ json: { error: 'Parameter "dateRangeStart" is required for event search (YYYY-MM-DD, today or future).' } }];
} else if (action === 'get_trails_by_criteria') {
  toolName = 'get_trails_by_criteria';
  toolArgs = buildArgs(['name', 'keywords', 'difficulty', 'max_length_km', 'region', 'is_circular', 'near_point']);
  if (toolArgs.max_length_km) toolArgs.max_length_km = Number(toolArgs.max_length_km);
  if (toolArgs.is_circular !== undefined) toolArgs.is_circular = toolArgs.is_circular === 'true' || toolArgs.is_circular === true;
} else if (action === 'get_entity_details') {
  toolName = 'get_entity_details';
  toolArgs = buildArgs(['uri', 'language']);
  if (!toolArgs.uri) return [{ json: { error: 'Parameter "uri" is required. Use a URI from a previous search result.' } }];
} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: get_pois_by_criteria, get_events_by_criteria, get_trails_by_criteria, get_entity_details.' } }];
}

try {
  // Step 1: Initialize MCP session
  const initResp = await helpers.httpRequest({
    method: 'POST',
    url: MCP_URL,
    headers: MCP_HEADERS,
    body: JSON.stringify({
      jsonrpc: '2.0', id: 1, method: 'initialize',
      params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'n8n-claw', version: '1.0' } }
    }),
    returnFullResponse: true,
    json: false,
    timeout: 15000
  });

  const sid = initResp.headers['mcp-session-id'];
  if (!sid) return [{ json: { error: 'DZT MCP server did not return session ID.' } }];

  // Step 2: Send initialized notification
  try {
    await helpers.httpRequest({
      method: 'POST', url: MCP_URL,
      headers: { ...MCP_HEADERS, 'mcp-session-id': sid },
      body: JSON.stringify({ jsonrpc: '2.0', method: 'notifications/initialized' }),
      json: false, timeout: 10000
    });
  } catch (e) { /* non-fatal */ }

  // Step 3: Call the tool
  const toolResp = await helpers.httpRequest({
    method: 'POST', url: MCP_URL,
    headers: { ...MCP_HEADERS, 'mcp-session-id': sid },
    body: JSON.stringify({
      jsonrpc: '2.0', id: 2, method: 'tools/call',
      params: { name: toolName, arguments: toolArgs }
    }),
    returnFullResponse: true,
    json: false,
    timeout: 30000
  });

  // Step 4: Parse SSE response
  const body = typeof toolResp.body === 'string' ? toolResp.body : JSON.stringify(toolResp.body);
  let rpcResult;
  if (body.includes('data: ')) {
    const lines = body.split('\n');
    for (const line of lines) {
      if (line.startsWith('data: ')) {
        try { rpcResult = JSON.parse(line.substring(6)); } catch (e) {}
      }
    }
  } else {
    try { rpcResult = typeof toolResp.body === 'object' ? toolResp.body : JSON.parse(body); } catch (e) {}
  }

  if (!rpcResult || !rpcResult.result) {
    return [{ json: { error: 'No result from DZT MCP server.', raw: body.substring(0, 500) } }];
  }

  // Step 5: Unwrap nested JSON-LD content
  // Structure: result.content[0].text -> JSON string -> [{type, text}] -> text is JSON-LD string
  const contentArr = rpcResult.result.content || [];
  if (contentArr.length === 0) return [{ json: { result: 'No results found.' } }];

  let rawText = contentArr[0].text || '';
  let jsonLd;
  try {
    let inner = JSON.parse(rawText);
    // inner is an array like [{type: 'text', text: '{...json-ld...}'}]
    if (Array.isArray(inner) && inner.length > 0 && inner[0].text) {
      jsonLd = JSON.parse(inner[0].text);
    } else if (typeof inner === 'object') {
      jsonLd = inner;
    }
  } catch (e) {
    // Try direct parse
    try { jsonLd = JSON.parse(rawText); } catch (e2) {
      return [{ json: { result: rawText.substring(0, 5000) } }];
    }
  }

  // Step 6: Extract entities from @graph
  const graph = jsonLd && jsonLd['@graph'] ? jsonLd['@graph'] : null;
  if (!graph || graph.length === 0) {
    return [{ json: { result: 'No results found for this query. Try broader search terms or a different region.' } }];
  }

  // Step 7: Format entities into readable text
  function cleanHtml(str) {
    if (!str) return '';
    return str.replace(/<[^>]*>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\\n/g, ' ').replace(/\s+/g, ' ').trim();
  }

  // Resolve JSON-LD value: handles plain strings, @value objects, and full URI keys
  function val(obj, ...keys) {
    for (const k of keys) {
      const v = obj[k];
      if (v === undefined || v === null) continue;
      if (typeof v === 'string') return v;
      if (typeof v === 'object' && v['@value']) return String(v['@value']);
      if (typeof v === 'object') return v;
    }
    return '';
  }

  function getType(entity) {
    const t = entity['@type'];
    if (!t) return '';
    const types = Array.isArray(t) ? t : [t];
    return types.map(x => x.replace('https://schema.org/', '').replace('https://odta.io/voc/', '')).filter(x => x !== 'Place' && x !== 'Thing').join(', ');
  }

  function fmtEntity(e) {
    const name = val(e, 'schema:name', 'https://schema.org/name', 'name') || '(unnamed)';
    const rawDesc = val(e, 'schema:description', 'https://schema.org/description', 'description') || '';
    const desc = cleanHtml(typeof rawDesc === 'string' ? rawDesc : '');
    const typeStr = getType(e);
    const addr = val(e, 'schema:address', 'https://schema.org/address', 'address') || {};
    const street = typeof addr === 'object' ? val(addr, 'schema:streetAddress', 'https://schema.org/streetAddress', 'streetAddress') : '';
    const locality = typeof addr === 'object' ? val(addr, 'schema:addressLocality', 'schema:adressLocality', 'https://schema.org/addressLocality', 'addressLocality') : '';
    const region = typeof addr === 'object' ? val(addr, 'schema:addressRegion', 'https://schema.org/addressRegion', 'addressRegion') : '';
    const postal = typeof addr === 'object' ? val(addr, 'schema:postalCode', 'https://schema.org/postalCode', 'postalCode') : '';
    const uri = e['@id'] || '';
    const startDate = val(e, 'schema:startDate', 'https://schema.org/startDate', 'startDate');
    const img = val(e, 'schema:image', 'https://schema.org/image');
    const imgUrl = (typeof img === 'object' && img) ? val(img, 'schema:contentUrl', 'https://schema.org/contentUrl', 'contentUrl') : '';
    const loc = val(e, 'schema:location', 'https://schema.org/location', 'location');
    let eventLocality = '', eventRegion = '';
    if (loc && typeof loc === 'object') {
      const locAddr = val(loc, 'schema:address', 'https://schema.org/address') || {};
      if (typeof locAddr === 'object') {
        eventLocality = val(locAddr, 'schema:addressLocality', 'https://schema.org/addressLocality') || '';
        eventRegion = val(locAddr, 'schema:addressRegion', 'https://schema.org/addressRegion') || '';
      }
    }

    let out = '## ' + name;
    if (typeStr) out += ' (' + typeStr + ')';
    out += '\n';
    if (desc) out += desc.substring(0, 300) + (desc.length > 300 ? '...' : '') + '\n';
    const addrParts = [street, postal, locality || eventLocality, region || eventRegion].filter(Boolean);
    if (addrParts.length > 0) out += 'Adresse: ' + addrParts.join(', ') + '\n';
    if (startDate) out += 'Datum: ' + startDate + '\n';
    if (imgUrl) out += 'Bild: ' + imgUrl + '\n';
    if (uri) out += 'URI: ' + uri + '\n';
    return out;
  }

  const total = graph.length;
  const shown = Math.min(total, 10);
  let result = total + ' Ergebnis' + (total !== 1 ? 'se' : '') + ' gefunden';
  if (total > shown) result += ' (zeige ' + shown + ')';
  result += ':\n\n';

  for (let i = 0; i < shown; i++) {
    result += fmtEntity(graph[i]) + '\n';
  }

  if (result.length > 5000) {
    result = result.substring(0, 5000) + '\n\n... (truncated, ' + result.length + ' chars total)';
  }

  return [{ json: { result } }];

} catch (err) {
  return [{ json: { error: 'DZT MCP call failed: ' + err.message } }];
}
